public function _add_control( $control_id = false, $control_args = [], $load_level = 100 ) {

	if (
		( $this->_load_level < $load_level
		  || 0 === $this->_load_level
		  || in_array( $control_id, $this->_exclude_controls )
		) && !in_array( $control_id, $this->_include_controls )
	) {
