	if ( function_exists( 'jet_styles_manager' ) && jet_styles_manager()->compatibility ) {
		$control_args = jet_styles_manager()->compatibility->set_control_args(
			$control_args,
			$load_level,
			'jet-elements'
		);
	}

	$this->add_control( $control_id, $control_args );
}

