   190→    /**
   191→     * Isola o <style> interno do SVG com um atributo data-scope único,
   192→     * evitando conflito de nomes de classes genéricas (ex: .cls-1) entre
   193→     * múltiplos SVGs inlined na mesma página.
   194→     *
   195→     * Escopo APENAS para SVGs que usam classes genéricas .cls-N.
   196→     * SVGs com classes únicas (ex: .SVGSpiral2026) são retornados sem modificação,
   197→     * preservando seus controles de estilo do Elementor e CSS interno complexo.
   198→     */
   199→    private function scope_svg_styles( string $svg, string $scope_id ): string {
   200→        // Só aplica scoping em SVGs com classes genéricas .cls-N
   201→        if ( ! preg_match( '/\.cls-[\w-]+\s*\{/', $svg ) ) {
   202→            return $svg;
   203→        }
   204→
   205→        // Injetar data-scope no elemento <svg>
   206→        $svg = preg_replace( '/<svg\b/', '<svg data-scope="' . esc_attr( $scope_id ) . '"', $svg, 1 );
   207→
   208→        // Scopar apenas os seletores .cls-* dentro dos blocos <style>
   209→        $svg = preg_replace_callback(
   210→            '/(<style[^>]*>)(.*?)(<\/style>)/is',
   211→            static function ( $m ) use ( $scope_id ) {
   212→                $scoped = preg_replace_callback(
   213→                    '/(\.cls-[\w-]+(?:\s*,\s*\.cls-[\w-]+)*)\s*\{/',
   214→                    static function ( $r ) use ( $scope_id ) {
   215→                        $selectors = array_map( 'trim', explode( ',', $r[1] ) );
   216→                        $prefixed  = array_map(
   217→                            static fn( $s ) => '[data-scope="' . $scope_id . '"] ' . $s,
   218→                            $selectors
   219→                        );
   220→                        return implode( ', ', $prefixed ) . ' {';
   221→                    },
   222→                    $m[2]
   223→                );
   224→                return $m[1] . $scoped . $m[3];
   225→            },
   226→            $svg
   227→        );
   228→
   229→        return $svg;
   230→    }
   231→
   232→    protected function render() {
   233→        $s = $this->get_settings_for_display();
   234→
   235→        $name = ! empty( $s['svg_name'] ) ? $s['svg_name'] : '';
   236→
   237→        if ( empty( $name ) ) return;
   238→
   239→        $file = get_stylesheet_directory() . '/svg/' . $name . '.svg';
   240→
   241→        if ( ! file_exists( $file ) ) return;
   242→
   243→        $svg = file_get_contents( $file );
   244→        if ( empty( $svg ) ) return;
   245→
   246→        // Remover declaração XML (inválida em HTML5 inline)
   247→        $svg = preg_replace( '/<\?xml[^?]*\?>\s*/i', '', $svg );
   248→
   249→        // Isolar CSS interno com data-scope para evitar conflitos entre SVGs inlined
   250→        $svg = $this->scope_svg_styles( $svg, 'bsvg-' . $this->get_id() );
   251→
   252→        // Injetar class no <svg>
   253→        if ( ! empty( $s['svg_class'] ) ) {
   254→            $class = esc_attr( $s['svg_class'] );
   255→            if ( preg_match( '/\bclass="[^"]*"/', $svg ) ) {
   256→                $svg = preg_replace( '/\bclass="([^"]*)"/', 'class="$1 ' . $class . '"', $svg, 1 );
   257→            } else {
   258→                $svg = preg_replace( '/<svg\b/', '<svg class="' . $class . '"', $svg, 1 );
   259→            }
   260→        }
   261→
   262→        // Injetar id no <svg>
   263→        if ( ! empty( $s['svg_id'] ) ) {
   264→            $id = esc_attr( $s['svg_id'] );
   265→            if ( preg_match( '/\bid="[^"]*"/', $svg ) ) {
   266→                $svg = preg_replace( '/\bid="[^"]*"/', 'id="' . $id . '"', $svg, 1 );
   267→            } else {
   268→                $svg = preg_replace( '/<svg\b/', '<svg id="' . $id . '"', $svg, 1 );
   269→            }
   270→        }
   271→
   272→        // Envolver em <a> se link_enabled = 'yes'
   273→        if ( ! empty( $s['link_enabled'] ) && $s['link_enabled'] === 'yes' ) {
   274→            $href   = ! empty( $s['link_url'] )
   275→                ? esc_url( $s['link_url'] )
   276→                : esc_url( apply_filters( 'wpml_home_url', network_home_url( '/' ) ) );
   277→            $target = ( $s['link_target'] ?? '_self' ) === '_blank'
   278→                ? ' target="_blank" rel="noopener noreferrer"'
   279→                : '';
   280→            $svg    = '<a href="' . $href . '"' . $target . '>' . $svg . '</a>';
   281→        }
   282→
   283→        echo $svg; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
   284→    }
   285→} // end class Bureau_SVG_Widget
   286→
   287→    $widgets_manager->register( new Bureau_SVG_Widget() );
   288→} ); // end add_action
