   453→	 *
   454→	 * @param array $attachment Media attachment.
   455→	 *
   456→	 * @return string Image title.
   457→	 */
   458→	public static function get_image_title( $attachment ) {
   459→		if ( empty( $attachment['id'] ) ) {
