        <span class="dropdown-btn-icon">...</span>
      </div>
    </a>
  </div>
</div>
```

### 3. WPML compatibility
Elementor + WPML Multilingual plugin handles translation of TEXT, MEDIA, URL, REPEATER controls automatically. No special code needed. The widget is already WPML-compatible as-is with standard controls. Just document this.

### 4. JetEngine meta repeater field support
Add a "data source" feature so the widget can read from a JetEngine meta repeater field (for use in JetEngine Listing Grid) instead of static Elementor data.

Controls to add in Content tab (after current repeater):
```php
// Source selector (shown always)
$this->add_control('data_source', [
    'label' => 'Fonte dos dados',
    'type' => \Elementor\Controls_Manager::SELECT,
    'default' => 'static',
    'options' => ['static' => 'Estático (Elementor)', 'meta_field' => 'Campo meta (JetEngine)'],
]);

// Meta key (shown only when data_source = meta_field)
$this->add_control('meta_key', [
    'label' => 'Nome do campo meta',
    'type' => \Elementor\Controls_Manager::TEXT,
    'condition' => ['data_source' => 'meta_field'],
    // e.g. 'arquivos_download'
]);

// Sub-field key mappings
$this->add_control('meta_key_label', [..., 'default' => 'label', 'condition' => ['data_source' => 'meta_field']]);
$this->add_control('meta_key_file_id', [..., 'default' => 'file_id', 'condition' => ['data_source' => 'meta_field']]);
$this->add_control('meta_key_fallback_url', [..., 'default' => 'fallback_url', 'condition' => ['data_source' => 'meta_field']]);
$this->add_control('meta_key_file_size', [..., 'default' => 'file_size', 'condition' => ['data_source' => 'meta_field']]);
```

Also wrap the existing `links` REPEATER control with `'condition' => ['data_source' => 'static']`.

Render logic for meta field source:
```php
if ( 'meta_field' === $s['data_source'] && ! empty( $s['meta_key'] ) ) {
    $raw = [];
    if ( function_exists('jet_engine') && ! empty( jet_engine()->listings ) && ! empty( jet_engine()->listings->data ) ) {
        $raw = jet_engine()->listings->data->get_meta( $s['meta_key'] );
    }
    if ( empty( $raw ) ) {
        $raw = get_post_meta( get_the_ID(), $s['meta_key'], true );
    }
    if ( is_string( $raw ) ) { $raw = maybe_unserialize( $raw ); }
    $links_raw = is_array( $raw ) ? $raw : [];

    $k_label    = ! empty( $s['meta_key_label'] )        ? $s['meta_key_label']        : 'label';
    $k_file_id  = ! empty( $s['meta_key_file_id'] )      ? $s['meta_key_file_id']      : 'file_id';
    $k_fallback = ! empty( $s['meta_key_fallback_url'] )  ? $s['meta_key_fallback_url'] : 'fallback_url';
    $k_size     = ! empty( $s['meta_key_file_size'] )     ? $s['meta_key_file_size']    : 'file_size';

    foreach ( $links_raw as $row ) {
        $links[] = [
            'item_label'        => $row[ $k_label ]    ?? '',
            'item_file'         => [ 'id' => (int) ( $row[ $k_file_id ] ?? 0 ), 'url' => '' ],
            'item_fallback_url' => [ 'url' => $row[ $k_fallback ] ?? '', 'is_external' => false ],
            'item_file_size'    => $row[ $k_size ] ?? '',
        ];
    }
} else {
    $links = $s['links'] ?? [];
}
```

### 5. File size display
Add `item_file_size` TEXT control to the repeater (always visible, not conditioned):
```php
$repeater->add_control('item_file_size', [
    'label'       => 'Tamanho do arquivo',
    'type'        => \Elementor\Controls_Manager::TEXT,
    'placeholder' => '3.2 MB',
    'ai'          => ['active' => false],
]);
